import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuthStore } from '../store/authStore';
import { useThemeStore } from '../store/themeStore';
import HourStackLogo from './HourStackLogo';
import './Navbar.css';

function SunIcon() {
  return (
    <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="4"/>
      <line x1="12" y1="2" x2="12" y2="6"/><line x1="12" y1="18" x2="12" y2="22"/>
      <line x1="4.93" y1="4.93" x2="7.76" y2="7.76"/><line x1="16.24" y1="16.24" x2="19.07" y2="19.07"/>
      <line x1="2" y1="12" x2="6" y2="12"/><line x1="18" y1="12" x2="22" y2="12"/>
      <line x1="4.93" y1="19.07" x2="7.76" y2="16.24"/><line x1="16.24" y1="7.76" x2="19.07" y2="4.93"/>
    </svg>
  );
}

function MoonIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>
    </svg>
  );
}

function Navbar() {
  const { isAuthenticated, isAdmin, logout } = useAuthStore();
  const { theme, toggleTheme } = useThemeStore();
  const navigate = useNavigate();
  const location = useLocation();

  const isActive = (path) => location.pathname === path;

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  if (!isAuthenticated) {
    return null;
  }

  return (
    <nav className="navbar">
      <div className="nav-container">
        <div className="nav-brand" onClick={() => navigate('/')}>
          <HourStackLogo size={38} />
          <span>HourStack</span>
        </div>
        
        <div className="nav-links">
          <a 
            href="/" 
            className={`nav-link ${isActive('/') ? 'active' : ''}`}
            onClick={(e) => { e.preventDefault(); navigate('/'); }}
          >
            Dashboard
          </a>
          <a 
            href="/projects" 
            className={`nav-link ${isActive('/projects') ? 'active' : ''}`}
            onClick={(e) => { e.preventDefault(); navigate('/projects'); }}
          >
            Projects
          </a>
          <a 
            href="/timelogs" 
            className={`nav-link ${isActive('/timelogs') ? 'active' : ''}`}
            onClick={(e) => { e.preventDefault(); navigate('/timelogs'); }}
          >
            Time Logs
          </a>
          <a 
            href="/invoices" 
            className={`nav-link ${isActive('/invoices') ? 'active' : ''}`}
            onClick={(e) => { e.preventDefault(); navigate('/invoices'); }}
          >
            Invoices
          </a>
          <a 
            href="/clients" 
            className={`nav-link ${isActive('/clients') ? 'active' : ''}`}
            onClick={(e) => { e.preventDefault(); navigate('/clients'); }}
          >
            Clients
          </a>
          {isAdmin && (
            <a
              href="/admin"
              className={`nav-link ${isActive('/admin') ? 'active' : ''}`}
              onClick={(e) => { e.preventDefault(); navigate('/admin'); }}
            >
              Admin
            </a>
          )}
          <button
            className="nav-theme-toggle"
            onClick={toggleTheme}
            title={theme === 'dark' ? 'Switch to light mode' : 'Switch to dark mode'}
            aria-label="Toggle theme"
          >
            {theme === 'dark' ? <SunIcon /> : <MoonIcon />}
          </button>
          <button className="nav-logout" onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
